render.css:
.iso-container { display: flex; align-items: center; justify-content: center; height: 180px; }
.iso-grid { display: grid; grid-template-columns: repeat(4, 24px); transform: rotateX(60deg) rotateZ(-45deg); transform-style: preserve-3d; }
.cube { position: relative; width: 24px; height: 24px; transform-style: preserve-3d; animation: cubeRise 3s ease-in-out infinite alternate; animation-delay: var(--delay); }
.cube-face { position: absolute; box-sizing: border-box; }
.cube-top { width: 24px; height: 24px; background: var(--ct-text-muted); border: 1px solid var(--ct-bg-deep); transform: translateZ(var(--h)); }
.cube-left { width: 24px; height: var(--h); background: var(--ct-surface-3); border: 1px solid var(--ct-bg-deep); transform-origin: bottom; transform: rotateX(-90deg) translateY(0px); top: 100%; }
.cube-right { width: var(--h); height: 24px; background: var(--ct-surface-2); border: 1px solid var(--ct-bg-deep); transform-origin: left; transform: rotateY(90deg); left: 100%; top: 0; }
@keyframes cubeRise { 0% { transform: translateZ(-10px); } 100% { transform: translateZ(10px); } }
